import { _decorator, Component, director, Node, Label, Button, Sprite } from 'cc';
import { GameManager } from '../Core/GameManager';

const { ccclass, property } = _decorator;

@ccclass('SailingScene')
export class SailingScene extends Component {
    @property(Button)
    backBtn: Button = null;
    
    @property(Button)
    sailBtn: Button = null;
    
    @property(Button)
    diveBtn: Button = null;
    
    @property(Label)
    shipLevelLabel: Label = null;
    
    @property(Label)
    oxygenLabel: Label = null;
    
    @property(Sprite)
    shipSprite: Sprite = null;
    
    @property(Label)
    explorationProgressLabel: Label = null;
    
    private shipTypes = [
        { name: '小渔船', level: 1, speed: 1, capacity: 100 },
        { name: '商船', level: 2, speed: 2, capacity: 300 },
        { name: '战船', level: 3, speed: 3, capacity: 500 },
        { name: '龙宫宝船', level: 4, speed: 5, capacity: 1000 }
    ];
    
    private currentShip = 0;
    private oxygen = 300; // 5分钟氧气（秒）
    private isDiving = false;
    
    onLoad() {
        this.backBtn.node.on(Button.EventType.CLICK, this.onBack, this);
        this.sailBtn.node.on(Button.EventType.CLICK, this.onSail, this);
        this.diveBtn.node.on(Button.EventType.CLICK, this.onDive, this);
    }
    
    start() {
        this.updateUI();
        this.schedule(this.updateOxygen, 1);
    }
    
    updateUI() {
        const ship = this.shipTypes[this.currentShip];
        this.shipLevelLabel.string = `当前船只: ${ship.name} (Lv.${ship.level})`;
        
        const mins = Math.floor(this.oxygen / 60);
        const secs = this.oxygen % 60;
        this.oxygenLabel.string = `氧气: ${mins}:${secs.toString().padStart(2, '0')}`;
        this.oxygenLabel.color = this.oxygen < 60 ? {r: 255, g: 0, b: 0, a: 255} : {r: 255, g: 255, b: 255, a: 255};
        
        this.diveBtn.interactable = !this.isDiving;
    }
    
    updateOxygen() {
        if (this.isDiving && this.oxygen > 0) {
            this.oxygen--;
            
            if (this.oxygen <= 0) {
                // 氧气耗尽，强制返回
                this.isDiving = false;
                alert('⚠️ 氧气耗尽！紧急上浮！');
            }
        }
        
        this.updateUI();
    }
    
    onSail() {
        // 航海探索
        const ship = this.shipTypes[this.currentShip];
        
        // 随机事件
        const events = [
            { name: '发现宝藏', reward: { incense_money: 1000 * ship.level } },
            { name: '遭遇海盗', reward: { incense_money: 500 } },
            { name: '平静航行', reward: { incense_money: 200 } },
            { name: '遇到商队', reward: { yuanbao: 10 * ship.level } }
        ];
        
        const event = events[Math.floor(Math.random() * events.length)];
        
        for (const [key, value] of Object.entries(event.reward)) {
            GameManager.getInstance().playerData.addCurrency(key, value);
        }
        
        alert(`航海事件: ${event.name}\n获得奖励！`);
    }
    
    onDive() {
        if (this.isDiving) return;
        
        this.isDiving = true;
        alert('开始潜水！氧气限制5分钟，寻找深海宝藏！');
        
        // 潜水探索
        let foundTreasures = 0;
        const diveInterval = setInterval(() => {
            if (!this.isDiving || this.oxygen <= 0) {
                clearInterval(diveInterval);
                return;
            }
            
            // 随机发现宝藏
            if (Math.random() < 0.3) {
                foundTreasures++;
                const reward = Math.floor(Math.random() * 500) + 200;
                GameManager.getInstance().playerData.addCurrency('incense_money', reward);
                console.log(`发现深海宝藏！+${reward}香火钱`);
            }
        }, 2000);
    }
    
    upgradeShip() {
        if (this.currentShip < this.shipTypes.length - 1) {
            this.currentShip++;
            alert(`船只升级！现在是${this.shipTypes[this.currentShip].name}`);
            this.updateUI();
        }
    }
    
    onBack() {
        this.isDiving = false;
        this.unscheduleAllCallbacks();
        director.loadScene('MainScene');
    }
    
    onDestroy() {
        this.unscheduleAllCallbacks();
    }
}
